(window.webpackJsonp=window.webpackJsonp||[]).push([[299],{581:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * @param {string[]} queries\\n * @param {string[]} words\\n * @return {number[]}\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> numSmallerByFrequency = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">queries, words</span>) </span>{\\n  \\n  <span class=\\"hljs-keyword\\">let</span> wordF=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> word <span class=\\"hljs-keyword\\">of</span> words){\\n    wordF.push(f(word))\\n  }\\n  <span class=\\"hljs-comment\\">// console.log(wordF)</span>\\n  <span class=\\"hljs-keyword\\">let</span> res=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;queries.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> curF=f(queries[i])\\n    <span class=\\"hljs-comment\\">// console.log(i,curF)</span>\\n    <span class=\\"hljs-keyword\\">let</span> count=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;wordF.length;j++){\\n      <span class=\\"hljs-keyword\\">if</span>(curF&lt;wordF[j])count++\\n    }\\n    res.push(count)\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">f</span>(<span class=\\"hljs-params\\">s</span>)</span>{\\n    s=s.split(<span class=\\"hljs-string\\">\'\'</span>).sort().join(<span class=\\"hljs-string\\">\'\'</span>)\\n    <span class=\\"hljs-keyword\\">let</span> count=<span class=\\"hljs-number\\">1</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;s.length;i++){\\n      <span class=\\"hljs-keyword\\">if</span>(s[i]!==s[i<span class=\\"hljs-number\\">-1</span>])<span class=\\"hljs-keyword\\">return</span> count\\n      count++\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> count\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"compare-strings-by-frequency-of-the-smallest-character","hasThinking":false,"content":"<p>\u6211\u4eec\u6765\u5b9a\u4e49\u4e00\u4e2a\u51fd\u6570&nbsp;<code>f(s)</code>\uff0c\u5176\u4e2d\u4f20\u5165\u53c2\u6570&nbsp;<code>s</code>&nbsp;\u662f\u4e00\u4e2a\u975e\u7a7a\u5b57\u7b26\u4e32\uff1b\u8be5\u51fd\u6570\u7684\u529f\u80fd\u662f\u7edf\u8ba1&nbsp;<code>s</code> &nbsp;\u4e2d\uff08\u6309\u5b57\u5178\u5e8f\u6bd4\u8f83\uff09\u6700\u5c0f\u5b57\u6bcd\u7684\u51fa\u73b0\u9891\u6b21\u3002</p>\\n\\n<p>\u4f8b\u5982\uff0c\u82e5&nbsp;<code>s = &quot;dcce&quot;</code>\uff0c\u90a3\u4e48&nbsp;<code>f(s) = 2</code>\uff0c\u56e0\u4e3a\u6700\u5c0f\u7684\u5b57\u6bcd\u662f&nbsp;<code>&quot;c&quot;</code>\uff0c\u5b83\u51fa\u73b0\u4e86&nbsp;2 \u6b21\u3002</p>\\n\\n<p>\u73b0\u5728\uff0c\u7ed9\u4f60\u4e24\u4e2a\u5b57\u7b26\u4e32\u6570\u7ec4\u5f85\u67e5\u8868&nbsp;<code>queries</code>&nbsp;\u548c\u8bcd\u6c47\u8868&nbsp;<code>words</code>\uff0c\u8bf7\u4f60\u8fd4\u56de\u4e00\u4e2a\u6574\u6570\u6570\u7ec4&nbsp;<code>answer</code>&nbsp;\u4f5c\u4e3a\u7b54\u6848\uff0c\u5176\u4e2d\u6bcf\u4e2a&nbsp;<code>answer[i]</code>&nbsp;\u662f\u6ee1\u8db3&nbsp;<code>f(queries[i])</code>&nbsp;&lt; <code>f(W)</code>&nbsp;\u7684\u8bcd\u7684\u6570\u76ee\uff0c<code>W</code>&nbsp;\u662f\u8bcd\u6c47\u8868&nbsp;<code>words</code>&nbsp;\u4e2d\u7684\u8bcd\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>queries = [&quot;cbd&quot;], words = [&quot;zaaaz&quot;]\\n<strong>\u8f93\u51fa\uff1a</strong>[1]\\n<strong>\u89e3\u91ca\uff1a</strong>\u67e5\u8be2 f(&quot;cbd&quot;) = 1\uff0c\u800c f(&quot;zaaaz&quot;) = 3 \u6240\u4ee5 f(&quot;cbd&quot;) &lt; f(&quot;zaaaz&quot;)\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>queries = [&quot;bbb&quot;,&quot;cc&quot;], words = [&quot;a&quot;,&quot;aa&quot;,&quot;aaa&quot;,&quot;aaaa&quot;]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,2]\\n<strong>\u89e3\u91ca\uff1a</strong>\u7b2c\u4e00\u4e2a\u67e5\u8be2 f(&quot;bbb&quot;) &lt; f(&quot;aaaa&quot;)\uff0c\u7b2c\u4e8c\u4e2a\u67e5\u8be2 f(&quot;aaa&quot;) \u548c f(&quot;aaaa&quot;) \u90fd &gt; f(&quot;cc&quot;)\u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= queries.length &lt;= 2000</code></li>\\n\\t<li><code>1 &lt;= words.length &lt;= 2000</code></li>\\n\\t<li><code>1 &lt;= queries[i].length, words[i].length &lt;= 10</code></li>\\n\\t<li><code>queries[i][j]</code>, <code>words[i][j]</code>&nbsp;\u90fd\u662f\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd</li>\\n</ul>\\n"}')}}]);